output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?drug ?drugLabel(GROUP_CONCAT(DISTINCT ?tradeName ; separator = ", ") AS ?tradeNames)(GROUP_CONCAT(DISTINCT ?sideEffectLabel ; separator = ", ") AS ?sideEffects) WHERE {
  ?drug wdt:P31 wd:Q334477 .
  ?drug rdfs:label ?drugLabel .
  FILTER(LANG(?drugLabel) = "en")
  .
  OPTIONAL {
    ?drug wdt:P782 ?tradeName
  }
  OPTIONAL {
    ?drug wdt:P1909 ?sideEffect .
    ?sideEffect rdfs:label ?sideEffectLabel .
    FILTER(LANG(?sideEffectLabel) = "en")
  }
}
GROUP BY ?drug ?drugLabel
LIMIT 10

